import React, { useState } from 'react';
import LoginPage from './components/LoginPage';
import RegisterPage from './components/RegisterPage';
import Dashboard from './components/Dashboard';

function App() {

    const [view, setView] = useState('main'); 


    const handleLoginSuccess = (token) => {
        localStorage.setItem('token', token); 
        setView('dashboard'); 
    };


    const handleRegisterSuccess = () => {
        alert("Konto założone! Teraz możesz się zalogować.");
        setView('login'); 
    };

    return (
        <div className="App">
            {view === 'main' && (
                <div className="welcome-screen">
                    <button onClick={() => setView('login')}>Zaloguj się</button>
                    <button onClick={() => setView('register')}>Zarejestruj się</button>
                </div>
            )}

            {view === 'login' && (
                <LoginPage onLoginSuccess={handleLoginSuccess} onSwitchToRegister={() => setView('register')} />
            )}

            {view === 'register' && (
                <RegisterPage onRegisterSuccess={handleRegisterSuccess} onSwitchToLogin={() => setView('login')} />
            )}

            {view === 'dashboard' && (
                <Dashboard onLogout={() => {
                    localStorage.removeItem('token');
                    setView('main');
                }} />
            )}
        </div>
    );
}

export default App;
